@interface WBGuideViewController ()<UICollectionViewDelegate, UICollectionViewDataSource, UIScrollViewDelegate>
@property (copy, nonatomic) WBGuidePageSetupCellHandler setupCellHandler;
@property (copy, nonatomic) WBGuidePageFinishHandler finishHandler;

@property (strong, nonatomic) UICollectionView *collectionView;
@property (strong, nonatomic) UIPageControl *pageControl;
@property (strong, nonatomic) NSString *nameStr;
@property (assign, nonatomic) NSInteger count;

@end
static NSString *const kStartPageCellId = @"kStartPageCellId";
@implementation WBGuideViewController

#pragma mark - lefe cycle
- (instancetype)initWithPagesCount:(NSInteger)count setupCellHandler:(WBGuidePageSetupCellHandler)setupCellHandler finishHandler:(WBGuidePageFinishHandler)finishHandler whichName:(NSString *)name {
    if (self = [super initWithNibName:nil bundle:nil]) {
        _count = count;
        _setupCellHandler = [setupCellHandler copy];
        _finishHandler = [finishHandler copy];
        // 添加collectionView -- 使用懒加载初始化
        [self.view addSubview:self.collectionView];
        // 添加pageControl  -- 使用懒加载初始化
        [self.view addSubview:self.pageControl];
        // 注册cell
        [self.collectionView registerClass:[WBGuidePageCell class] forCellWithReuseIdentifier:kStartPageCellId];
        self.nameStr = name;
    }
    return self;
}
#pragma mark - UICollectionViewDataSource
- (NSInteger)collectionView:(UICollectionView *)collectionView numberOfItemsInSection:(NSInteger)section {
    return self.count;
}

- (UICollectionViewCell *)collectionView:(UICollectionView *)collectionView cellForItemAtIndexPath:(NSIndexPath *)indexPath {
    WBGuidePageCell *cell = [collectionView dequeueReusableCellWithReuseIdentifier:kStartPageCellId forIndexPath:indexPath];
    if (indexPath.row != self.count-1) {
        cell.isEnd = NO;
        cell.finishBtn.hidden = NO;
        cell.remindBtn.hidden = YES;
        [cell.finishBtn setTitle:@"下一步" forState:UIControlStateNormal];
        [cell.finishBtn addTarget:self action:@selector(nextStep:) forControlEvents:UIControlEventTouchUpInside];
    }
    else {
        // 随后一页 显示按钮, 并且添加响应方法
        cell.isEnd = YES;
        cell.finishBtn.hidden = NO;
        cell.remindBtn.hidden = NO;
        [cell.finishBtn setTitle:@"我知道了" forState:UIControlStateNormal];
        [cell.remindBtn setTitle:@"不再提醒" forState:UIControlStateNormal];
        [cell.finishBtn addTarget:self action:@selector(finishBtnOnClick:) forControlEvents:UIControlEventTouchUpInside];
        [cell.remindBtn addTarget:self action:@selector(remindBtnOnClick:) forControlEvents:UIControlEventTouchUpInside];
    }
    // 设置数据
    if (self.setupCellHandler) {
        self.setupCellHandler(cell, indexPath);
    }
    return cell;
}
-(void)nextStep:(WBGuidePageCell *)guideCell{
    _pageControl.numberOfPages = self.count+1;
    NSInteger currentPage = self.scrollView.contentOffset.x/self.scrollView.bounds.size.width + 0.5;
    if (self.pageControl.currentPage != currentPage) {
        self.pageControl.currentPage = currentPage;
    }
    CGPoint offset = self.collectionView.contentOffset;
    offset.x +=WBScreenWidth;
    [self.collectionView setContentOffset:offset animated:YES];
}
- (void)finishBtnOnClick:(UIButton *)finishBtn {
    if (self.finishHandler) {
        self.finishHandler(finishBtn);
    }
}
- (void)remindBtnOnClick:(UIButton *)finishBtn {
    [WBSettingManager.sharedManager setSkipGuideForFeature:self.nameStr];
    if (self.finishHandler) {
        self.finishHandler(finishBtn);
    }
}
-(void)collectionView:(UICollectionView *)collectionView didSelectItemAtIndexPath:(NSIndexPath *)indexPath{
    _pageControl.numberOfPages = self.count+1;
}
#pragma mark - UIScrollViewDelegate
- (void)scrollViewDidScroll:(UIScrollView *)scrollView {
    // 向下取整
    NSInteger currentPage = scrollView.contentOffset.x/scrollView.bounds.size.width + 0.5;
    if (self.pageControl.currentPage != currentPage) {
        self.pageControl.currentPage = currentPage;
    }
}
#pragma mark - getter

- (UICollectionView *)collectionView {
    if (!_collectionView) {
        UICollectionViewFlowLayout *layout = [UICollectionViewFlowLayout new];
        layout.scrollDirection = UICollectionViewScrollDirectionHorizontal;
        layout.itemSize = self.view.bounds.size;
        layout.minimumLineSpacing = 0.f;
        layout.minimumInteritemSpacing = 0.f;

        UICollectionView *collectionView = [[UICollectionView alloc] initWithFrame:self.view.bounds collectionViewLayout:layout];
        collectionView.pagingEnabled = YES;
        collectionView.bounces = NO;
        collectionView.showsHorizontalScrollIndicator = NO;
        collectionView.delegate = self;
        collectionView.dataSource = self;
        _collectionView = collectionView;
    }
    return _collectionView;
}

- (UIPageControl *)pageControl {
    if (!_pageControl) {
        UIPageControl *pageControl = [[UIPageControl alloc] init];
        pageControl.numberOfPages = self.count;
        pageControl.currentPage = 0;
        CGSize pageControlSize = [pageControl sizeForNumberOfPages:self.count];
        CGFloat pageControlX = (self.view.bounds.size.width - pageControlSize.width)/2;
        // 距离屏幕下方为 50 请根据具体情况修改吧
        CGFloat pageControlY = (self.view.bounds.size.height - pageControlSize.height - 50.f);
        pageControl.frame = CGRectMake(pageControlX, pageControlY, pageControlSize.width, pageControlSize.height);
        _pageControl = pageControl;
    }
    return _pageControl;
}
-(void)viewWillAppear:(BOOL)animated{
    [super viewWillAppear:animated];
    [self removeSplashImageView];
}
-(void)removeSplashImageView {
    UIWindow *window = [[UIApplication sharedApplication].delegate window];
    for (UIView *view in window.subviews) {
        if ([view isKindOfClass:[UIImageView class]]) {
            [view removeFromSuperview];
        }
    }
}

@end

