- (void)requestVAppCallbackInterfaceWithURL:(NSString *)url params:(NSDictionary *)params callback:(WBVAppCallback)callback {
    [self POST:url params:params callback:^(id  _Nullable json, NSError * _Nullable error) {
        if (error) return callback(nil, error);
        NSAssert(json, @"json is null");
        WBVAppDetailHttpModel *vAppModel = [WBVAppDetailHttpModel modelWithJSON:json];
        return callback(vAppModel, nil);
    }];
}

- (void)requestVAppListCallbackInterfaceWithURL:(NSString *)url params:(NSDictionary *)params callback:(WBVAppListCallback)callback {
    [self POST:url params:params callback:^(id  _Nullable json, NSError * _Nullable error) {
        if (error) return callback(nil, error);
        NSArray<WBVAppBaseHttpModel *> *vApps = [NSArray modelArrayWithClass:[WBVAppBaseHttpModel class] json:json[@"list"]];
        return callback(vApps, nil);
    }];
}

- (void)requestFeedbackListCallbackInterfaceWithURL:(NSString *)url params:(NSDictionary *)params callback:(WBFeedbackListCallback)callback {
    [self POST:url params:params callback:^(id  _Nullable json, NSError * _Nullable error) {
        [self checkoutFeedbackListResponseWithError:error responseJSON:json sourceInterface:url callback:callback];
    }];
}

- (void)requestMultipartFeedbackListCallbackInterfaceWithURL:(NSString *)url params:(NSDictionary *)params callback:(WBFeedbackListCallback)callback {
    [self multipartRequest:url params:params callback:^(id  _Nullable json, NSError * _Nullable error) {
        [self checkoutFeedbackListResponseWithError:error responseJSON:json sourceInterface:url callback:callback];
    }];
}

- (void)checkoutFeedbackListResponseWithError:(NSError *)error responseJSON:(id)json sourceInterface:(nullable NSString *)sourceInterface callback:(WBFeedbackListCallback)callback {
    if (error) return callback(nil, json);
    NSArray<NSDictionary *> *feedbackDicts = [self extractListFromResponseJSONContainingList:json];
    NSArray<WBFeedbackModel *> *feedbackModels = [WBFeedbackModel modelsWithDicts:feedbackDicts sourceInterface:sourceInterface];
    return callback(feedbackModels, nil);
}

- (NSArray *)extractListFromResponseJSONContainingList:(id)responseJSON {
    NSArray<NSDictionary *> *list = responseJSON[@"list"];
    NSAssert(list, @"json no 'list'");
    return list;
}

