#import "WBMinePrivilegeButton.h"

@implementation WBMinePrivilegeButton

- (instancetype)initWithIsBelongToSVIP:(BOOL)belongToSVIP icon:(NSString *)iconName name:(NSString *)name desc:(NSString *)descString tip:(NSString *)tipString {
    self = [super init];
    if (self) {
        self.belongToSVIP = belongToSVIP;
        self.iconName = iconName;
        self.name = name;
        self.desc = descString;
        self.tipString = tipString;
        [self setupUI];
    }
    return self;
}

- (instancetype)initWithIsBelongToSVIP:(BOOL)belongToSVIP icon:(NSString *)iconName name:(NSString *)name desc:(NSString *)descString tipDescription:(NSString *)tipDescription trialTimes:(NSInteger)trialTimes {
    self = [super init];
    if (self) {
        self.belongToSVIP = belongToSVIP;
        self.iconName = iconName;
        self.name = name;
        self.desc = descString;
        self.tipString = [self getTipStringWithTipDescription:tipDescription trialTimes:trialTimes];
        [self setupUI];
    }
    return self;
}


#pragma mark - setupUI

- (void)setupUI {
    [self addSubviews];
    [self addAllConstraints];
    self.clipsToBounds = NO;
    _tipLabel.hidden = (_tipString && ![_tipString isEqualToString:@""]) ? NO : YES;
    _tipImageView.hidden = _tipLabel.hidden;
}

- (void)addSubviews {
    [self addSubview:self.iconImageView];
    [self addSubview:self.nameLabel];
    [self addSubview:self.tipImageView];
    [self addSubview:self.tipLabel];
}

- (void)addAllConstraints {
    [_iconImageView mas_makeConstraints:^(MASConstraintMaker *make) {
        NSInteger topSpace = self.belongToSVIP ? ZOOM(10) : 0;
        make.top.equalTo(self).offset(topSpace);
        make.centerX.equalTo(self);
        make.width.height.mas_equalTo(ZOOM(32));
    }];

    [_nameLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        NSInteger topSpace = self.belongToSVIP ? ZOOM(8) : ZOOM(4);
        make.top.equalTo(self.iconImageView.mas_bottom).offset(topSpace);
        make.centerX.equalTo(self);
    }];

    [_tipImageView mas_makeConstraints:^(MASConstraintMaker *make) {
        NSInteger leftSpace = self.belongToSVIP ? ZOOM(4) : ZOOM(-9);
        NSInteger topSpace = self.belongToSVIP ? ZOOM(-6) : ZOOM(-10);
        make.left.equalTo(self.iconImageView.mas_right).offset(leftSpace);
        make.top.equalTo(self.iconImageView).offset(topSpace);
        make.height.mas_equalTo(ZOOM(16));
        make.width.greaterThanOrEqualTo(self.tipLabel.mas_width).offset(ZOOM(8));
    }];

    [_tipLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.center.equalTo(self.tipImageView);
    }];
}


#pragma mark - events

- (NSString *)getTipStringWithTipDescription:(NSString *)tipDescription trialTimes:(NSInteger)trialTimes {
    if (trialTimes > 0) {
        NSString *trialTimesString = [NSString stringWithFormat:@"%ld次试用", (long)trialTimes];
        return trialTimesString;
    }
    if (tipDescription && ![tipDescription isEqualToString:@""]) {
        return tipDescription;
    }
    return nil;
}

- (void)updateWithIcon:(NSString *)iconName name:(NSString *)name desc:(NSString *)desc {
    if (iconName && iconName.length > 0) {
        self.iconImageView.image = [UIImage imageNamed:iconName];
        self.iconName = iconName;
    }
    if (name && name.length > 0) {
        self.nameLabel.text = name;
        self.name = name;
    }
    if (desc && desc.length > 0) {
        self.desc = desc;
    }
}


#pragma mark - lazy load

- (UIImageView *)iconImageView {
    if (!_iconImageView) {
        _iconImageView = [[UIImageView alloc] initWithImage:[UIImage imageNamed:self.iconName]];
        _iconImageView.layer.cornerRadius = ZOOM(16);
        _iconImageView.clipsToBounds = YES;
    }
    return _iconImageView;
}

- (UILabel *)nameLabel {
    if (!_nameLabel) {
        _nameLabel = [[UILabel alloc] init];
        _nameLabel.text = self.name;
        _nameLabel.textColor = WBColorHex(0x3F4A6F);
        _nameLabel.font = WBPrimaryBoldFont(14);
    }
    return _nameLabel;
}

- (UIImageView *)tipImageView {
    if (!_tipImageView) {
        _tipImageView = [[UIImageView alloc] initWithImage:[UIImage imageNamed:@"MinePagePrivilegeLabelImage"]];
    }
    return _tipImageView;
}

- (UILabel *)tipLabel {
    if (!_tipLabel) {
        _tipLabel = [[UILabel alloc] init];
        _tipLabel.text = self.tipString ?: @"";
        _tipLabel.textColor = WBColorHex(0xFFFFFF);
        _tipLabel.font = WBPrimaryBoldFont(10);
    }
    return _tipLabel;
}


@end

