- (void)updateWithVAppDetailModel:(WBVAppDetailHttpModel*)model {
    WBVAppVersionInfo *versionInfo = [WBVAppVersionInfo initWithVAppDetailModel:model];
    versionInfo.prevVersion = self.versionInfo.version;
    self.versionInfo = versionInfo;

    // Record current osVersion and engineVersion
    WBVAppLaunchInfo *launchInfo = [[WBVAppLaunchInfo alloc] init];
    launchInfo.osVersion = [WBQuery query].osVersion;
    launchInfo.engineVersion = [WBQuery query].engineVersion;
    self.launchInfo = launchInfo;

    // Init vapp error info
    WBVAppErrorInfo *errorInfo = [[WBVAppErrorInfo alloc] init];
    errorInfo.errorType = WBVappStatusNone;
    errorInfo.errorDomain = @"";
    errorInfo.errorCode = 0;
    errorInfo.errorMessage = @"";
    self.errorInfo = errorInfo;

    // Init vapp features switch status
    WBVAppFeatureStatus *featureStatusInfo = [[WBVAppFeatureStatus alloc] init];
    featureStatusInfo.isLockSwitchOn = NO;
    featureStatusInfo.isNotificationSwitchOn = NO;
    featureStatusInfo.isDisguiseSwitchOn = NO;
    featureStatusInfo.isPretenseSwitchOn = NO;
    featureStatusInfo.isOneClickSwitchOn = NO;
    self.featureStatusInfo = featureStatusInfo;
}

- (void)setInMemoryStatus:(WBVappStatus)status {
    if (status & (WBVappStatusWaitingDownload | WBVappStatusDownloadError | WBVappStatusInstallError | WBVappStatusResourceDownloadError | WBVappStatusResourceInstallError)) {
        _progress = 0.0;
    } else if (status & (WBVappStatusDownloaded | WBVappStatusInstalled | WBVappStatusResourceDownloaded | WBVappStatusResourceInstalled)) {
        _progress = 1.0f;
    }

    // 清理 errorInfo
    if (!(status & (WBVappStatusDownloadError | WBVappStatusInstallError | WBVappStatusResourceDownloadError | WBVappStatusResourceInstallError | WBVappStatusInitError))) {
        _errorInfo.errorType = WBVappStatusNone;
        _errorInfo.errorDomain = @"";
        _errorInfo.errorCode = 0;
        _errorInfo.errorMessage = @"";
    }

    [self setStatus:status];
}

- (void)setStatus:(WBVappStatus)status {
    if (_status == status) return;
    NSLog(@"vapp%@, status:%d -> %d", _name, (int)log2(_status), (int)log2(status));
    _status = status;
}

- (void)saveError:(WBVappStatus)errorType errorDomain:(NSString *)errorDomain errorCode:(NSInteger)errorCode errorMessage:(NSString *)errorMessage {
