#import "WBMinePopViewController.h"

@interface WBMinePopViewController ()

@property (nonatomic, copy) NSString *titleString;
@property (nonatomic, copy) NSString *lockedIcon;
@property (nonatomic, copy) NSString *descString;
@property (nonatomic, copy) NSString *featureBit;
@property (nonatomic, copy) NSString *cancelText;
@property (nonatomic, copy) void (^setBtnBlock)(void);

@end

@implementation WBMinePopViewController

- (instancetype)initWithTitle:(NSString *)title locked_icon:(NSString *)locked_icon desc:(NSString *)desc featureBit:(NSString *)featureBit {
    return [self initWithTitle:title locked_icon:locked_icon desc:desc featureBit:featureBit cancelText:@"" setBtnAction:^{}];
}

- (instancetype)initWithTitle:(NSString *)title locked_icon:(NSString *)locked_icon desc:(NSString *)desc featureBit:(NSString *)featureBit cancelText:(NSString *)cancelText setBtnAction:(void(^)(void))setBtnBlock {
    self = [super init];
    if (self) {
        _titleString = [title copy];
        _lockedIcon = [locked_icon copy];
        _descString = [desc copy];
        _featureBit = [featureBit copy];
        _cancelText = [cancelText copy];
        _setBtnBlock = [setBtnBlock copy];
        [self configureView];
    }
    return self;
}

- (void)configureView {
    // 配置弹窗内容
    self.titleLabel.text = self.titleString;
    self.headImageView.image = [UIImage imageNamed:self.lockedIcon];
    self.contentLabel.text = self.descString;

    // 计算文本高度和布局
    CGFloat maxWidth = ZOOM(172);
    CGFloat desHigh = [[self class] getLabelHeightWithText:self.descString width:ZOOM(168) font:14];
    CGFloat actualWidth = [[self class] getLabelWidthWithText:self.descString font:14];

    if (actualWidth < maxWidth) {
        self.contentLabel.textAlignment = NSTextAlignmentCenter;
    }

    NSUInteger bit = (NSUInteger)[self.featureBit integerValue];
    BOOL hasBenefit = bit > 0 && ((WBSettingManager.sharedManager.Benefit & bit) != 0);

    // 按权益状态判断按钮配置
    if (hasBenefit) {
        if (kStringIsEmpty(self.cancelText)) {
            self.setBtn.hidden = YES;
            [self.popView mas_makeConstraints:^(MASConstraintMaker *make) {
                make.height.mas_equalTo(ZOOM(156) + desHigh);
            }];
        } else {
            [self.setBtn setTitle:self.cancelText forState:UIControlStateNormal];
            self.setBtn.titleLabel.font = WBPrimaryFont(14);
            [self.setBtn setTitleColor:[UIColor whiteColor] forState:UIControlStateNormal];
            self.setBtn.backgroundColor = [UIColor blackColor];
            [self.popView mas_makeConstraints:^(MASConstraintMaker *make) {
                make.height.mas_equalTo(ZOOM(200) + desHigh);
            }];
        }
    } else {
        [self.setBtn setTitle:@"马上解锁" forState:UIControlStateNormal];
        self.setBtn.backgroundColor = BlueColor_b;
        [self.setBtn setTitleColor:[UIColor whiteColor] forState:UIControlStateNormal];
        [self.popView mas_makeConstraints:^(MASConstraintMaker *make) {
            make.height.mas_equalTo(ZOOM(200) + desHigh);
        }];
    }

    __weak typeof(self) weakSelf = self;
    [self.setBtn addBlockForControlEvents:UIControlEventTouchUpInside block:^(id _Nonnull sender) {
        NSUInteger currentBit = (NSUInteger)[weakSelf.featureBit integerValue];
        BOOL hasCurrentBenefit = currentBit > 0 && ((WBSettingManager.sharedManager.Benefit & currentBit) != 0);
        if (!hasCurrentBenefit) {
            if ([weakSelf.delegate respondsToSelector:@selector(popViewControllerDidTapUnlockButton)]) {
                [weakSelf.delegate popViewControllerDidTapUnlockButton];
            }
        }

        if (weakSelf.setBtnBlock) {
            weakSelf.setBtnBlock();
        }
        [weakSelf dismiss];
    }];
}


#pragma mark - tools

+ (CGFloat)getLabelHeightWithText:(NSString *)text width:(CGFloat)width font:(CGFloat)font {
    CGRect rect = [text boundingRectWithSize:CGSizeMake(width, MAXFLOAT) options:NSStringDrawingUsesLineFragmentOrigin attributes:@{NSFontAttributeName:FONT_14} context:nil];
    return rect.size.height;
}

// 计算文本实际宽度
+ (CGFloat)getLabelWidthWithText:(NSString *)text font:(CGFloat)font {
    CGRect rect = [text boundingRectWithSize:CGSizeMake(MAXFLOAT, MAXFLOAT)
                                     options:NSStringDrawingUsesLineFragmentOrigin
                                  attributes:@{NSFontAttributeName : WBPrimaryFont(font)}
                                     context:nil];
    return rect.size.width;
}


@end

