    if (isSkip) {
        self.navigationController.tabBarController.hidesBottomBarWhenPushed=NO;
        self.navigationController.tabBarController.selectedIndex = 0;
    } else {
        NSArray *imageArr;
        if (kArrayIsEmpty([WBVAppManager sharedManager].myApps)) {
            imageArr = guideArr;
        }else{
            imageArr = nonguideArr;
        }
        __block UIViewController *oldRootVC = [WBAppManager getUIApplicationKeywindow].rootViewController;
        WBGuideViewController *startVc = [[WBGuideViewController alloc] initWithPagesCount:imageArr.count setupCellHandler:^(WBGuidePageCell *cell, NSIndexPath *indexPath) {
            UIImage *im = [UIImage imageNamed:imageArr[indexPath.row]];
            cell.imageView.image = im;
        } finishHandler:^(UIButton *finishBtn) {
            [WBAppManager getUIApplicationKeywindow].rootViewController = oldRootVC;
        } whichName:name];
        startVc.pageControl.pageIndicatorTintColor = [UIColor clearColor];
        startVc.pageControl.currentPageIndicatorTintColor = [UIColor clearColor];
        [[WBAppManager getUIApplicationKeywindow] makeKeyAndVisible];
        [WBAppManager getUIApplicationKeywindow].rootViewController = startVc;
    }
}


