#pragma mark - events

- (void)onBackgroundViewTapped:(UIGestureRecognizer *)gesture {
    [self dismiss];
}

- (void)show {
    UIViewController *topVC = [self topMostViewController];
    [topVC addChildViewController:self];
    [topVC.view addSubview:self.view];
    [self.view layoutSubviews];
    self.view.alpha = 1.0;
}

- (void)dismiss {
    self.view.alpha = 0;
    [self removeFromParentViewController];
    [self.view removeFromSuperview];
}

- (UIViewController *)topMostViewController {
    UIViewController *rootVc = [WBAppManager getUIApplicationRootViewController];
    return [self findTopMostViewController:rootVc];
}

- (UIViewController *)findTopMostViewController:(UIViewController *)vc {
    if (vc.presentedViewController) {
        return [self findTopMostViewController:vc.presentedViewController];
    } else if ([vc isKindOfClass:[UINavigationController class]]) {
        UINavigationController *navController = (UINavigationController *)vc;
        return [self findTopMostViewController:navController.visibleViewController];
    } else if ([vc isKindOfClass:[UITabBarController class]]) {
        UITabBarController *tabBarController = (UITabBarController *)vc;
        return [self findTopMostViewController:tabBarController.selectedViewController];
    } else {
        return vc;
    }
}


