@implementation WBMinePrivilegeView

- (instancetype)initWithFrame:(CGRect)frame {
    self = [super initWithFrame:frame];
    if (self) {
        self.features = [WBVIPFeatureManager.sharedManager getFeatures];
        [self setupUI];
    }
    return self;
}


#pragma mark - setUpUI

- (void)setupUI {
    self.backgroundColor = [UIColor clearColor];
    [self addSubviews];
    [self setupButtons];
    [self addAllConstraints];
}

- (void)addSubviews {
    [self addSubview:self.titleImageView];
    [self addSubview:self.powerView];
    [self.powerView addSubview:self.svipPowerView];
    [self.powerView addSubview:self.vipPowerView];
    [self.powerView addSubview:self.seperatorView];
    [self addSubview:self.onlySvipLabelImageView];
}

- (void)setupButtons {
    // 获取当前会员状态的配置
    NSDictionary *config = [self vipStatusConfig];
    NSString *nameKey = config[@"nameKey"];
    NSString *descKey = config[@"descKey"];

    // 创建按钮的辅助方法
    WBMinePrivilegeButton* (^createButton)(NSString *codeName, BOOL isSVIP) = ^WBMinePrivilegeButton*(NSString *codeName, BOOL isSVIP) {
        WBVIPFeatureModel *featureModel = nil;
        for (WBVIPFeatureModel *feature in self.features) {
            if ([feature.code_name isEqualToString:codeName]) {
                featureModel = feature;
                break;
            }
        }

        if (featureModel) {
            NSString *benefitDescription = nil;
            NSInteger benefitTrialTimes = 0;
            if (WBSettingManager.sharedManager.IsNew && WBSettingManager.sharedManager.BenefitTrialProperties.count > 0) {
                for (NSDictionary *dict in WBSettingManager.sharedManager.BenefitTrialProperties) {
                    NSInteger currentBenefitBit = [dict[@"benefitBit"] integerValue];
                    if (currentBenefitBit == [featureModel.bit integerValue]) {
                        id descObject = dict[@"desc"];
                        id trialTimesObject = dict[@"trialTimes"];
                        if (trialTimesObject && trialTimesObject != [NSNull null]) {
                            benefitTrialTimes = [WBSettingManager.sharedManager trialUsageTimesForBenefitBit:[featureModel.bit integerValue]];
                        } else if (descObject) {
                            benefitDescription = [dict[@"desc"] stringValue];
                        }
                        break;
                    }
                }
            }

            BOOL hasTheBenefit = (WBSettingManager.sharedManager.Benefit & [featureModel.bit unsignedIntegerValue]);
            NSString *featureName = ([featureModel valueForKey:nameKey] && hasTheBenefit) ? [featureModel valueForKey:nameKey] : featureModel.name;
            NSString *featureDescription = ([featureModel valueForKey:descKey] && hasTheBenefit) ? [featureModel valueForKey:descKey] : featureModel.desc;

            // 动态获取对应会员状态和视图类型的图标key
            NSString *iconKey = [self iconKeyForViewType:isSVIP featureBit:featureModel.bit];
            NSString *featureIcon = [featureModel valueForKey:iconKey];

            WBMinePrivilegeButton *button;
            if (WBSettingManager.sharedManager.IsNew && WBSettingManager.sharedManager.BenefitTrialProperties.count > 0) {
                button = [[WBMinePrivilegeButton alloc] initWithIsBelongToSVIP:isSVIP icon:featureIcon name:featureName desc:featureDescription tipDescription:benefitDescription trialTimes:benefitTrialTimes];
            } else {
                button = [[WBMinePrivilegeButton alloc] initWithIsBelongToSVIP:isSVIP icon:featureIcon name:featureName desc:featureDescription tip:@""];
            }
            button.featureCodeName = codeName;
            [button addTarget:self action:@selector(privilegeButtonClicked:) forControlEvents:UIControlEventTouchUpInside];

            return button;
        }
        return nil;
    };

    // SVIP的按钮
    NSMutableArray *svipButtonsArray = [NSMutableArray array];
    NSArray *svipFeatureCodes = @[@"adsfree", @"pretense", @"oneclick"];

    for (NSString *codeName in svipFeatureCodes) {
        WBMinePrivilegeButton *button = createButton(codeName, YES);
        if (button) {
            [svipButtonsArray addObject:button];
        }
    }
    self.svipButtons = [svipButtonsArray copy];

    // VIP的按钮
    NSMutableArray *vipButtonsArray = [NSMutableArray array];
    NSArray *vipFeatureCodes = @[@"infinite", @"lock", @"disguise", @"notification"];

    for (NSString *codeName in vipFeatureCodes) {
        WBMinePrivilegeButton *button = createButton(codeName, NO);
        if (button) {
            [vipButtonsArray addObject:button];
        }
    }
    self.vipButtons = [vipButtonsArray copy];

    // 将按钮添加到对应的视图
    for (WBMinePrivilegeButton *button in self.svipButtons) {
        [self.svipPowerView addSubview:button];
    }

    for (WBMinePrivilegeButton *button in self.vipButtons) {
        [self.vipPowerView addSubview:button];
    }
}

- (void)addAllConstraints {
    [_titleImageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.top.equalTo(self);
        make.width.mas_equalTo(ZOOM(92));
        make.height.mas_equalTo(ZOOM(20));
    }];

    [_powerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.right.bottom.equalTo(self);
        make.height.mas_equalTo(ZOOM(168));
    }];

    [_svipPowerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.left.right.equalTo(self.powerView);
        make.height.mas_equalTo(ZOOM(80));
    }];

    [_vipPowerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.svipPowerView.mas_bottom).offset(ZOOM(16));
        make.left.right.equalTo(self.powerView);
        make.bottom.equalTo(self.powerView).offset(ZOOM(-16));
    }];

    [_seperatorView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.right.bottom.equalTo(self.powerView);
        make.height.mas_equalTo(ZOOM(0.5));
    }];

    [_onlySvipLabelImageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.equalTo(self.powerView);
        make.bottom.equalTo(self.powerView.mas_top);
        make.width.mas_equalTo(ZOOM(75));
        make.height.mas_equalTo(ZOOM(24));
    }];

    [self setupButtonsConstraintsElegantly];
}

- (void)setupButtonsConstraintsElegantly {
    NSArray *buttonConfigs = @[
        @{@"buttons": self.svipButtons, @"container": self.svipPowerView},
        @{@"buttons": self.vipButtons, @"container": self.vipPowerView}
    ];

    for (NSDictionary *config in buttonConfigs) {
        NSArray *buttons = config[@"buttons"];
        UIView *container = config[@"container"];
        [self setupAutoLayoutForButtons:buttons inContainer:container];
    }
}

- (void)setupAutoLayoutForButtons:(NSArray<UIView *> *)buttons inContainer:(UIView *)container {
    if (buttons.count == 0) return;

    [container mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.right.equalTo(self.powerView);
    }];

    // 按钮等宽布局
    UIView *previousView = nil;
    for (UIView *button in buttons) {
        [button mas_makeConstraints:^(MASConstraintMaker *make) {
            make.top.bottom.equalTo(container);

            if (previousView) {
                make.left.equalTo(previousView.mas_right);
                make.width.equalTo(previousView);
            } else {
                make.left.equalTo(container);
            }

            if (button == buttons.lastObject) {
                make.right.equalTo(container);
            }
        }];

        previousView = button;
    }
}


#pragma mark - 按钮点击事件

- (void)privilegeButtonClicked:(WBMinePrivilegeButton *)button {
    [button showClickedAnimationWithLevel:5];

    // 直接通过featureCodeName查找特征模型
    WBVIPFeatureModel *featureModel = nil;
    if (button.featureCodeName) {
        for (WBVIPFeatureModel *feature in self.features) {
            if ([feature.code_name isEqualToString:button.featureCodeName]) {
                featureModel = feature;
                break;
            }
        }
    }

    if (!featureModel) {
        return;
    }

    NSInteger index = [self.features indexOfObject:featureModel];
    if (index == NSNotFound) {
        return;
    }

    // 优先使用代理，其次使用block
    if ([self.delegate respondsToSelector:@selector(privilegeView:didSelectButtonAtIndex:withTitle:icon:desc:featureBit:)]) {
        [self.delegate privilegeView:self
               didSelectButtonAtIndex:index
                            withTitle:button.name
                                 icon:button.iconName
                                 desc:button.desc
                           featureBit:featureModel.bit ?: @"0"];
    } else if (self.clickBlock) {
        self.clickBlock(index);
    }
}


#pragma mark - events

- (void)updateUI {
    NSDictionary *config = [self vipStatusConfig];
    _titleImageView.image = [UIImage imageNamed:config[@"titleImageName"]];
    _onlySvipLabelImageView.image = [UIImage imageNamed:config[@"onlySVIPImageName"]];
    [self updateButtonsForVipStatus];
}

- (void)updateButtonsForVipStatus {
    NSDictionary *config = [self vipStatusConfig];
    NSString *nameKey = config[@"nameKey"];
    NSString *descKey = config[@"descKey"];

    // 更新SVIP按钮
    for (WBMinePrivilegeButton *button in self.svipButtons) {
        [self updateSingleButton:button isSVIPButton:YES nameKey:nameKey descKey:descKey];
    }

    // 更新VIP按钮
    for (WBMinePrivilegeButton *button in self.vipButtons) {
        [self updateSingleButton:button isSVIPButton:NO nameKey:nameKey descKey:descKey];
    }
}

- (void)updateSingleButton:(WBMinePrivilegeButton *)button isSVIPButton:(BOOL)isSVIPButton nameKey:(NSString *)nameKey descKey:(NSString *)descKey {
    if (!button.featureCodeName) return;

    WBVIPFeatureModel *featureModel = nil;
    for (WBVIPFeatureModel *feature in self.features) {
        if ([feature.code_name isEqualToString:button.featureCodeName]) {
            featureModel = feature;
            break;
        }
    }

    if (!featureModel) return;

    BOOL hasTheBenefit = (WBSettingManager.sharedManager.Benefit & [featureModel.bit unsignedIntegerValue]);
    NSString *featureName = ([featureModel valueForKey:nameKey] && hasTheBenefit) ? [featureModel valueForKey:nameKey] : featureModel.name;
    NSString *featureDescription = ([featureModel valueForKey:descKey] && hasTheBenefit) ? [featureModel valueForKey:descKey] : featureModel.desc;
    NSString *iconKey = [self iconKeyForViewType:isSVIPButton featureBit:featureModel.bit];
    NSString *featureIcon = [featureModel valueForKey:iconKey];
    [button updateWithIcon:featureIcon name:featureName desc:featureDescription];

    if (WBSettingManager.sharedManager.IsNew && WBSettingManager.sharedManager.BenefitTrialProperties.count > 0) {
        NSString *tipText = nil;
        BOOL showTip = NO;
        for (NSDictionary *dict in WBSettingManager.sharedManager.BenefitTrialProperties) {
            NSInteger currentBenefitBit = [dict[@"benefitBit"] integerValue];
            if (currentBenefitBit == [featureModel.bit integerValue]) {
                id trialTimesObject = dict[@"trialTimes"];
                if (trialTimesObject && trialTimesObject != [NSNull null]) {
                    NSInteger times = [WBSettingManager.sharedManager trialUsageTimesForBenefitBit:[featureModel.bit integerValue]];
                    if (times > 0) {
                        tipText = [NSString stringWithFormat:@"%ld次试用", (long)times];
                        showTip = YES;
                    }
                } else {
                    id descObject = dict[@"desc"];
                    if (descObject) {
                        tipText = [dict[@"desc"] stringValue];
                        showTip = tipText.length > 0;
                    }
                }
                break;
            }
        }
        button.tipLabel.text = tipText ?: @"";
        button.tipLabel.hidden = !showTip;
        button.tipImageView.hidden = !showTip;
    }
}


